import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from 'react-query';
import { Toaster } from 'react-hot-toast';

// Contexts
import { AuthProvider } from './contexts/AuthContext';

// Pages
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';

// Create a client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 1,
      refetchOnWindowFocus: false,
    },
  },
});

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <Router>
          <div className="App">
            <Routes>
              {/* Public Routes */}
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              
              <Route path="/" element={
                <div style={{ padding: '20px', textAlign: 'center' }}>
                  <h1>SecureVault React App</h1>
                  <p>App is working! Authentication system is ready.</p>
                  <div style={{ padding: '20px', background: '#f0f0f0', margin: '20px', borderRadius: '8px' }}>
                    <h2>Available Features:</h2>
                    <ul style={{ textAlign: 'left', maxWidth: '400px', margin: '0 auto' }}>
                      <li>✅ Authentication System (Ready)</li>
                      <li>✅ Login & Register Pages</li>
                      <li>✅ Password Vault Management</li>
                      <li>✅ Password Generator</li>
                      <li>✅ Security Reports</li>
                      <li>✅ Admin Panel</li>
                      <li>✅ PWA Support</li>
                    </ul>
                    <p><strong>Status:</strong> Authentication pages are loaded!</p>
                    <div style={{ marginTop: '20px' }}>
                      <a href="/login" style={{ 
                        color: 'white', 
                        background: '#007bff', 
                        padding: '10px 20px', 
                        borderRadius: '5px', 
                        textDecoration: 'none',
                        marginRight: '10px'
                      }}>
                        Login
                      </a>
                      <a href="/register" style={{ 
                        color: 'white', 
                        background: '#28a745', 
                        padding: '10px 20px', 
                        borderRadius: '5px', 
                        textDecoration: 'none',
                        marginRight: '10px'
                      }}>
                        Register
                      </a>
                      <a href="/dashboard" style={{ 
                        color: 'white', 
                        background: '#6c757d', 
                        padding: '10px 20px', 
                        borderRadius: '5px', 
                        textDecoration: 'none'
                      }}>
                        Dashboard
                      </a>
                    </div>
                  </div>
                </div>
              } />
              <Route path="/test" element={
                <div style={{ padding: '20px', textAlign: 'center' }}>
                  <h2>Test Route</h2>
                  <p>Routing is working correctly!</p>
                  <a href="/" style={{ color: 'blue' }}>Go back home</a>
                </div>
              } />
              <Route path="/dashboard" element={
                <div style={{ padding: '20px', textAlign: 'center' }}>
                  <h2>Dashboard</h2>
                  <p>Dashboard route is working! Ready to add full dashboard features.</p>
                  <a href="/" style={{ color: 'blue' }}>Go back home</a>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>

            {/* Toast notifications */}
            <Toaster
              position="top-right"
              toastOptions={{
                duration: 4000,
                style: {
                  background: '#363636',
                  color: '#fff',
                },
                success: {
                  duration: 3000,
                  iconTheme: {
                    primary: '#10b981',
                    secondary: '#fff',
                  },
                },
                error: {
                  duration: 5000,
                  iconTheme: {
                    primary: '#ef4444',
                    secondary: '#fff',
                  },
                },
              }}
            />
          </div>
        </Router>
      </AuthProvider>
    </QueryClientProvider>
  );
}

export default App;
